import React, { useState, useEffect } from "react";

const PdfViewer = () => {
  const [pdfList, setPdfList] = useState([]);
  const [selectedPdf, setSelectedPdf] = useState("");
  const [pdfContent, setPdfContent] = useState("");
  const [analysisResult, setAnalysisResult] = useState("");
  const [isPdfVisible, setIsPdfVisible] = useState(false);

  useEffect(() => {
    const fetchPdfList = async () => {
      try {
        const response = await fetch("http://localhost:8000/pdfs");
        const data = await response.json();
        setPdfList(data.pdf_files || []);
      } catch (error) {
        console.error("Error fetching PDFs:", error);
      }
    };

    fetchPdfList();
  }, []);

  const handlePdfSelection = async (event) => {
    const selected = event.target.value;
    setSelectedPdf(selected);
    setIsPdfVisible(!!selected);

    try {
      const response = await fetch(
        `http://localhost:8000/pdf-content?filename=${selected}`
      );
      const data = await response.json();
      setPdfContent(data.content);
    } catch (error) {
      console.error("Error fetching PDF content:", error);
    }

    return (


      <div className="right-panel">
        {selectedPdf && (
          <object
            data={`http://localhost:8000/pdfs/${selectedPdf}`}
            type="application/pdf"
            width="100%"
            height="100%"
            style={{ border: "none", minHeight: "800px" }}
          />
        )}
      </div>)
  };

  const handleAnalyze = async () => {
    try {
      const response = await fetch("http://localhost:8000/analyze-section", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          pdf: selectedPdf,
          section: "summary",
          custom_prompt: "",
        }),
      });
      const data = await response.json();
      setAnalysisResult(data.content);
    } catch (error) {
      console.error("Error analyzing PDF:", error);
    }
  };

  return (


      <div className="right-panel">
        {selectedPdf && (
          <object
            data={`http://localhost:8000/pdfs/${selectedPdf}`}
            type="application/pdf"
            width="100%"
            height="100%"
            style={{ border: "none", minHeight: "800px" }}
          />
        )}
      </div>
    //</div>
  );
};

export default PdfViewer;
